import React from 'react';

export default function Counter({ value, onChange, min = -Infinity, max = Infinity, step = 1 }) {
  const clamp = (n) => Math.min(max, Math.max(min, n));
  const dec = () => onChange(clamp(value - step));
  const inc = () => onChange(clamp(value + step));

  const btn = {
    width: 40,
    height: 40,
    fontSize: 20,
    cursor: 'pointer',
    border: '1px solid #ccc',
    background: '#f7f7f7',
    borderRadius: 6,
  };

  return (
    <div style={{ display: 'inline-flex', alignItems: 'center', gap: 12 }}>
      <button
        style={{ ...btn, opacity: value <= min ? 0.4 : 1 }}
        onClick={dec}
        disabled={value <= min}
        aria-label="Decrement"
      >
        −
      </button>
      <span
        aria-live="polite"
        style={{ minWidth: 40, textAlign: 'center', fontSize: 20, fontWeight: 600 }}
      >
        {value}
      </span>
      <button
        style={{ ...btn, opacity: value >= max ? 0.4 : 1 }}
        onClick={inc}
        disabled={value >= max}
        aria-label="Increment"
      >
        +
      </button>
    </div>
  );
}

