import { Component, Input, Output, EventEmitter } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-counter',
  template: `
    <div style="display: inline-flex; align-items: center; gap: 12px;">
      <button
        (click)="dec()"
        [disabled]="value <= min"
        [style.opacity]="value <= min ? 0.4 : 1"
        style="width: 40px; height: 40px; font-size: 20px; cursor: pointer; border: 1px solid #ccc; background: #f7f7f7; border-radius: 6px;"
        aria-label="Decrement"
      >−</button>
      <span aria-live="polite" style="min-width: 40px; text-align: center; font-size: 20px; font-weight: 600;">{{ value }}</span>
      <button
        (click)="inc()"
        [disabled]="value >= max"
        [style.opacity]="value >= max ? 0.4 : 1"
        style="width: 40px; height: 40px; font-size: 20px; cursor: pointer; border: 1px solid #ccc; background: #f7f7f7; border-radius: 6px;"
        aria-label="Increment"
      >+</button>
    </div>
  `,
})
export class CounterComponent {
  @Input() value = 0;
  @Input() min = -Infinity;
  @Input() max = Infinity;
  @Input() step = 1;
  @Output() valueChange = new EventEmitter<number>();

  private clamp(n: number): number {
    return Math.min(this.max, Math.max(this.min, n));
  }

  inc(): void {
    this.valueChange.emit(this.clamp(this.value + this.step));
  }

  dec(): void {
    this.valueChange.emit(this.clamp(this.value - this.step));
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Counter Demo</h1>
      <app-counter [value]="count" (valueChange)="count = $event" [min]="0" [max]="10" [step]="1"></app-counter>
      <p style="margin-top: 16px; font-size: 18px;">Current value: <strong>{{ count }}</strong></p>
    </div>
  `,
})
export class AppComponent {
  count = 0;
}

@NgModule({
  declarations: [AppComponent, CounterComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
